export const query = graphql`
  query($slug: String!) {
    markdownRemark(frontmatter: { slug: { eq: $slug } }) {
      frontmatter {
        date(
          formatString: "DD MMMM YYYY"
          locale: "fr-FR"
        )
        slug
        title
      }
      html
    }
  }
`
